const data = $input.first().json;

if (!data.found_match) {
  return [{
    json: {
      ...data,
      should_create_a: false,
      should_create_b: false
    }
  }];
}

const originalStart = data.original_check_in;
const originalEnd = data.original_check_out;
const releaseStart = data.release_start;
const releaseEnd = data.release_end;

const shouldCreateA = originalStart < releaseStart;
const shouldCreateB = releaseEnd < originalEnd;

function makeBookingId(suffix) {
  const today = new Date().toISOString().slice(2, 10).replace(/-/g, '');
  const random = Math.floor(1000 + Math.random() * 9000);
  return `WH-${today}-${suffix}-${random}`;
}

return [{
  json: {
    ...data,

    should_create_a: shouldCreateA,
    should_create_b: shouldCreateB,

    block_a_booking_id: shouldCreateA ? makeBookingId('A') : null,
    block_a_check_in: shouldCreateA ? originalStart : null,
    block_a_check_out: shouldCreateA ? releaseStart : null,

    block_b_booking_id: shouldCreateB ? makeBookingId('B') : null,
    block_b_check_in: shouldCreateB ? releaseEnd : null,
    block_b_check_out: shouldCreateB ? originalEnd : null,

    split_note: `Operator released room from ${releaseStart} to ${releaseEnd}. Original block ${data.original_booking_id} split.`
  }
}];

const data = $input.first().json;

const bookingBeds =
  data.original_fields?.['Booking Beds'] ||
  data.fields?.['Booking Beds'] ||
  $('Code - Prepare Split Operator Blocks').first().json.original_fields?.['Booking Beds'] ||
  [];

// If there are no Booking Bed records, return no items.
// This prevents the Airtable "Cancel Original Booking Bed" node from running
// without a valid booking_bed_record_id.
if (!Array.isArray(bookingBeds) || bookingBeds.length === 0) {
  return [];
}

return bookingBeds
  .filter(id => !!id)
  .map(id => ({
    json: {
      ...data,
      booking_bed_record_id: id
    }
  }));

const release = $('Get Release Request').first().json.fields;

const roomToRelease = Array.isArray(release['Room to Release'])
  ? release['Room to Release'][0]
  : release['Room to Release'];

const releaseStart = release['Release Start Date'];
const releaseEnd = release['Release End Date'];

function overlaps(originalStart, originalEnd, releaseStart, releaseEnd) {
  return originalStart < releaseEnd && releaseStart < originalEnd;
}

const matches = $input.all().filter(item => {
  const f = item.json.fields || item.json;

  const roomToBlock = Array.isArray(f['Room to Block'])
    ? f['Room to Block'][0]
    : f['Room to Block'];

  return (
    f['Booking Source'] === 'Operator' &&
    f['Block Type'] === 'Whole Room' &&
    f['Operator Name'] === release['Operator'] &&
    roomToBlock === roomToRelease &&
    overlaps(f['Check In'], f['Check Out'], releaseStart, releaseEnd)
  );
});

if (matches.length !== 1) {
  return [{
    json: {
      found_match: false,
      match_count: matches.length,
      request_record_id: $('Get Release Request').first().json.id,
      error_notes: matches.length === 0
        ? 'No matching operator room block found.'
        : 'Multiple matching operator room blocks found.'
    }
  }];
}

const original = matches[0].json;
const fields = original.fields || original;

return [{
  json: {
    found_match: true,
    request_record_id: $('Get Release Request').first().json.id,
    original_booking_record_id: original.id,
    original_booking_id: fields['Booking ID'],
    original_check_in: fields['Check In'],
    original_check_out: fields['Check Out'],
    release_start: releaseStart,
    release_end: releaseEnd,
    operator: release['Operator'],
    room_to_release: roomToRelease,
    room_to_block: roomToRelease,
    original_fields: fields
  }
}];

